+		InReplyTo:"<id>\r\n",
+	}); err == nil {
+		t.Fatalf("expected invalid Reply-To error")
+	}
+	if _, err := buildRFC822(mailOptions{
+		From:       "a@b.com",
+		To:         []string{"c@d.com"},
+		Subject:    "Hi",
