+		t.Fatalf("expected invalid References error")
+	}
+	if _, err := buildRFC822(mailOptions{
+		From:    "a@b.com",
+		To:      []string{"c@d.com"},
+		Subject: "Hi\r\n",
+		Body:    "Hello",
+	}); err == nil {
